'use client';

import { useEffect, useMemo, useState } from 'react';
import Link from 'next/link';
import { fetcher } from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import { Listing } from '../../types';
import { supabase } from '../../utils/supabase';

type AdminStats = {
  listingsCount: number;
  usersCount: number;
  verifiedSellersCount: number;
  messagesCount: number;
};

export default function AdminDashboardPage() {
  const { user, loading: authLoading } = useAuth();
  const [isAdmin, setIsAdmin] = useState(false);
  const [checkingAdmin, setCheckingAdmin] = useState(false);
  const [pendingRequests, setPendingRequests] = useState<any[]>([]);
  const [loadingRequests, setLoadingRequests] = useState(false);
  const [stats, setStats] = useState<AdminStats | null>(null);
  const [listings, setListings] = useState<Listing[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const isAuthed = !authLoading && !!user;

  useEffect(() => {
    if (!isAuthed) return;

    const load = async () => {
      setCheckingAdmin(true);
      setError(null);
      try {
        // Admin access is granted when the user has an approved `admin_requests` row.
        const { data: adminReq, error: adminReqError } = await supabase
          .from('admin_requests')
          .select('status')
          .eq('user_id', user.id)
          .eq('status', 'approved')
          .maybeSingle();

        if (adminReqError) throw adminReqError;
        const approved = !!adminReq;
        setIsAdmin(approved);

        if (!approved) return;

        // Load pending admin requests + dashboard data.
        setLoading(true);
        setLoadingRequests(true);

        const [pending, statsData, listingsData] = await Promise.all([
          supabase
            .from('admin_requests')
            .select('user_id,user_name,user_email,user_avatar,requested_at')
            .eq('status', 'pending')
            .order('requested_at', { ascending: false })
            .limit(50),
          fetcher('/admin/stats'),
          fetcher('/admin/listings?limit=12'),
        ]);

        if (pending.error) throw pending.error;
        setPendingRequests(pending.data || []);
        setStats(statsData);
        setListings(listingsData);
      } catch (e: any) {
        setError(e?.message || 'Failed to load admin dashboard');
        setIsAdmin(false);
      } finally {
        setCheckingAdmin(false);
        setLoadingRequests(false);
        setLoading(false);
      }
    };

    load();
  }, [isAuthed]);

  const handleApprove = async (userId: string) => {
    const ok = confirm('Approve this user as admin?');
    if (!ok) return;

    try {
      await supabase
        .from('admin_requests')
        .update({
          status: 'approved',
          approved_at: new Date().toISOString(),
        })
        .eq('user_id', userId);

      // Refresh pending list only.
      const pending = await supabase
        .from('admin_requests')
        .select('user_id,user_name,user_email,user_avatar,requested_at')
        .eq('status', 'pending')
        .order('requested_at', { ascending: false })
        .limit(50);

      if (pending.error) throw pending.error;
      setPendingRequests(pending.data || []);
    } catch (e: any) {
      setError(e?.message || 'Failed to approve request');
    }
  };

  const formattedStats = useMemo(() => {
    if (!stats) return null;
    return [
      { label: 'Listings', value: stats.listingsCount, hint: 'Total active & historical ads' },
      { label: 'Users', value: stats.usersCount, hint: 'Registered accounts' },
      {
        label: 'Verified sellers',
        value: stats.verifiedSellersCount,
        hint: 'Accounts with verification enabled',
      },
      { label: 'Messages', value: stats.messagesCount, hint: 'All chat messages' },
    ];
  }, [stats]);

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this listing?')) return;
    try {
      await fetcher(`/admin/listings/${id}`, { method: 'DELETE' });
      // Refresh list after deletion.
      const listingsData = await fetcher('/admin/listings?limit=12');
      setListings(listingsData);
    } catch (e: any) {
      setError(e?.message || 'Failed to delete listing');
    }
  };

  if (!isAuthed || checkingAdmin || loading) {
    if (!isAuthed) {
      return (
        <div className="max-w-6xl mx-auto py-10">
          <div className="bg-white/80 backdrop-blur border border-gray-200/70 ring-1 ring-gray-100 rounded-3xl shadow-sm p-8">
            <h1 className="text-2xl font-bold text-gray-900 mb-2">Admin access required</h1>
            <p className="text-gray-600 mb-6">Please sign in.</p>
            <Link
              href="/login"
              className="inline-flex items-center justify-center bg-gradient-to-r from-blue-600 to-indigo-600 text-white px-5 py-3 rounded-xl font-semibold hover:brightness-110 transition-[filter] ring-1 ring-blue-200/30"
            >
              Go to Login
            </Link>
          </div>
        </div>
      );
    }

    return (
      <div className="max-w-6xl mx-auto py-10">
        <div className="bg-white/80 backdrop-blur border border-gray-200/70 ring-1 ring-gray-100 rounded-3xl shadow-sm p-8">
          Checking admin privileges...
        </div>
      </div>
    );
  }

  if (!isAdmin) {
    return (
      <div className="max-w-6xl mx-auto py-10">
        <div className="bg-white/80 backdrop-blur border border-gray-200/70 ring-1 ring-gray-100 rounded-3xl shadow-sm p-8">
          <h1 className="text-2xl font-bold text-gray-900 mb-2">Not an admin</h1>
          <p className="text-gray-600 mb-6">
            Only approved admins can access this page.
          </p>
          <Link
            href="/profile"
            className="inline-flex items-center justify-center bg-gradient-to-r from-blue-600 to-indigo-600 text-white px-5 py-3 rounded-xl font-semibold hover:brightness-110 transition-[filter] ring-1 ring-blue-200/30"
          >
            Go to Profile
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto py-10">
      <div className="bg-white/70 backdrop-blur border border-gray-200/70 ring-1 ring-gray-100 rounded-3xl shadow-sm p-6 md:p-8">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3 mb-6">
          <div>
            <h1 className="text-3xl font-extrabold tracking-tight text-gray-900">Admin Dashboard</h1>
            <p className="text-gray-600 mt-1">Monitor marketplace activity and moderate listings.</p>
          </div>

          <div className="flex gap-2 flex-wrap">
            <Link
              href="/listings"
              className="inline-flex items-center justify-center px-4 py-2 rounded-xl border border-gray-200/70 bg-white/50 hover:bg-white transition-colors text-sm font-semibold text-gray-700"
            >
              View Public Listings
            </Link>
          </div>
        </div>

        {error && (
          <div className="mb-5 bg-red-50 text-red-700 border border-red-200 rounded-2xl px-4 py-3">
            {error}
          </div>
        )}

        <div className="mb-8">
          <div className="flex items-center justify-between gap-4 mb-3">
            <div>
              <div className="font-extrabold text-gray-900 text-lg">Pending admin requests</div>
              <div className="text-sm text-gray-600">Approve to grant access to `/admin`.</div>
            </div>
          </div>

          <div className="rounded-2xl border border-gray-200/70 bg-white/60 overflow-hidden">
            <div className="p-4 border-b border-gray-200/70 bg-gray-50/40">
              {pendingRequests.length === 0 ? 'No pending requests' : `Total: ${pendingRequests.length}`}
            </div>
            <div className="overflow-auto">
              <table className="w-full text-sm">
                <thead className="bg-gray-50">
                  <tr className="text-left text-gray-600">
                    <th className="p-3 font-semibold">User</th>
                    <th className="p-3 font-semibold">Requested</th>
                    <th className="p-3 font-semibold">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {pendingRequests.map((r) => (
                    <tr key={r.user_id} className="border-t border-gray-200/70">
                      <td className="p-3">
                        <div className="flex items-center gap-3">
                          <img
                            src={r.user_avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(r.user_name || 'User')}`}
                            alt=""
                            className="h-8 w-8 rounded-full ring-1 ring-gray-200 object-cover"
                          />
                          <div>
                            <div className="font-semibold text-gray-900 line-clamp-1">{r.user_name || 'Unknown'}</div>
                            <div className="text-xs text-gray-500">{r.user_email || r.user_id}</div>
                          </div>
                        </div>
                      </td>
                      <td className="p-3 text-gray-700">
                        {r.requested_at ? new Date(r.requested_at).toLocaleString() : '—'}
                      </td>
                      <td className="p-3">
                        <button
                          onClick={() => handleApprove(r.user_id)}
                          className="inline-flex items-center justify-center px-4 py-2 rounded-xl bg-gradient-to-r from-blue-600 to-indigo-600 text-white text-xs font-semibold hover:brightness-110 transition-[filter] ring-1 ring-blue-200/30"
                        >
                          Approve
                        </button>
                      </td>
                    </tr>
                  ))}
                  {pendingRequests.length === 0 && (
                    <tr>
                      <td colSpan={3} className="p-6 text-center text-gray-500">
                        Nothing to approve.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {loading || !formattedStats ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
            {[1, 2, 3, 4].map((i) => (
              <div
                key={i}
                className="h-28 rounded-2xl bg-gray-100 animate-pulse ring-1 ring-gray-200/60"
              />
            ))}
          </div>
        ) : (
          <>
            <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4 mb-8">
              {formattedStats.map((s) => (
                <div
                  key={s.label}
                  className="rounded-2xl border border-gray-200/70 bg-white/60 p-5 shadow-sm"
                >
                  <div className="text-sm font-semibold text-gray-600">{s.label}</div>
                  <div className="text-3xl font-extrabold text-gray-900 mt-2">{s.value}</div>
                  <div className="text-xs text-gray-500 mt-1">{s.hint}</div>
                </div>
              ))}
            </div>

            <div className="rounded-2xl border border-gray-200/70 bg-white/60 overflow-hidden">
              <div className="p-4 border-b border-gray-200/70 flex items-center justify-between gap-3">
                <div>
                  <div className="font-bold text-gray-900">Latest Listings</div>
                  <div className="text-sm text-gray-600">Click delete to remove an ad.</div>
                </div>
              </div>

              <div className="overflow-auto">
                <table className="w-full text-sm">
                  <thead className="bg-gray-50">
                    <tr className="text-left text-gray-600">
                      <th className="p-3 font-semibold">Title</th>
                      <th className="p-3 font-semibold">Price</th>
                      <th className="p-3 font-semibold">Location</th>
                      <th className="p-3 font-semibold">Seller</th>
                      <th className="p-3 font-semibold">Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {listings.length === 0 ? (
                      <tr>
                        <td colSpan={5} className="p-6 text-center text-gray-500">
                          No listings found.
                        </td>
                      </tr>
                    ) : (
                      listings.map((l) => (
                        <tr key={l.id} className="border-t border-gray-200/70">
                          <td className="p-3">
                            <div className="font-semibold text-gray-900 line-clamp-1">
                              {l.title}
                            </div>
                            <div className="text-xs text-gray-500">
                              {l.category?.replace('_', ' ') || '—'}
                            </div>
                          </td>
                          <td className="p-3 font-bold text-blue-700">${l.price.toLocaleString()}</td>
                          <td className="p-3 text-gray-700">{l.location}</td>
                          <td className="p-3 text-gray-700">
                            <div className="inline-flex items-center gap-2">
                              <img
                                src={l.user?.avatar || `https://ui-avatars.com/api/?name=${l.user?.name || 'User'}`}
                                alt=""
                                className="h-7 w-7 rounded-full ring-1 ring-gray-200 object-cover"
                              />
                              <span className="truncate max-w-[160px] inline-block align-middle">
                                {l.user?.name || 'Seller'}
                              </span>
                            </div>
                          </td>
                          <td className="p-3">
                            <div className="flex gap-2">
                              <Link
                                href={`/listings/${l.id}`}
                                className="inline-flex items-center justify-center px-3 py-2 rounded-xl border border-gray-200/70 bg-white/70 hover:bg-white transition-colors text-xs font-semibold text-gray-700"
                              >
                                View
                              </Link>
                              <button
                                onClick={() => handleDelete(l.id)}
                                className="inline-flex items-center justify-center px-3 py-2 rounded-xl bg-red-50 border border-red-200 text-red-700 hover:bg-red-100 transition-colors text-xs font-semibold"
                              >
                                Delete
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

'use client';

import { useEffect, useMemo, useState } from 'react';
import Link from 'next/link';
import { useAuth } from '../../../context/AuthContext';
import { supabase } from '../../../utils/supabase';
import { Button } from '../../../components/ui/button';
import { Card, CardContent } from '../../../components/ui/card';
import { Badge } from '../../../components/ui/badge';

type AdminRequest = {
  status: 'pending' | 'approved' | 'rejected';
  requested_at?: string;
  approved_at?: string;
};

export default function AdminRequestPage() {
  const { user, loading } = useAuth();
  const [request, setRequest] = useState<AdminRequest | null>(null);
  const [loadingRequest, setLoadingRequest] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isAuthed = !loading && !!user;

  useEffect(() => {
    if (!user) {
      setRequest(null);
      return;
    }

    setLoadingRequest(true);
    setError(null);

    supabase
      .from('admin_requests')
      .select('status, requested_at, approved_at')
      .eq('user_id', user.id)
      .maybeSingle()
      .then(({ data, error }) => {
        if (error) throw error;
        setRequest(data as any);
      })
      .catch((e: any) => {
        setError(e?.message || 'Failed to load admin request');
        setRequest(null);
      })
      .finally(() => setLoadingRequest(false));
  }, [user]);

  const statusLabel = useMemo(() => {
    if (!request?.status) return 'Not requested';
    if (request.status === 'approved') return 'Approved';
    if (request.status === 'pending') return 'Pending';
    return 'Rejected';
  }, [request]);

  const handleRequestAdmin = async () => {
    if (!user) return;
    setError(null);
    setLoadingRequest(true);

    const user_metadata = (user as any).user_metadata || {};

    try {
      await supabase.from('admin_requests').upsert(
        {
          user_id: user.id,
          user_name: user_metadata.name || '',
          user_email: user.email || '',
          user_phone: user_metadata.phone || null,
          user_avatar: user_metadata.avatar || null,
          status: 'pending',
          requested_at: new Date().toISOString(),
        },
        { onConflict: 'user_id' }
      );

      const { data, error } = await supabase
        .from('admin_requests')
        .select('status, requested_at, approved_at')
        .eq('user_id', user.id)
        .maybeSingle();

      if (error) throw error;
      setRequest(data as any);
    } catch (e: any) {
      setError(e?.message || 'Failed to submit admin request');
    } finally {
      setLoadingRequest(false);
    }
  };

  if (!isAuthed) {
    return (
      <div className="max-w-3xl mx-auto py-10 px-4">
        <div className="bg-white/80 backdrop-blur border border-gray-200/70 rounded-3xl ring-1 ring-gray-100 shadow-sm p-8">
          <h1 className="text-2xl font-bold text-gray-900 mb-2">Login required</h1>
          <p className="text-gray-600 mb-6">Please sign in to request admin access.</p>
          <Button render={<Link href="/login" />} className="rounded-xl">
            Go to Login
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <Card className="rounded-[2.5rem] border-gray-200/70 bg-white/70 backdrop-blur shadow-sm">
        <CardContent className="p-6 md:p-8 space-y-6">
          <div className="flex items-start justify-between gap-4">
            <div>
              <h1 className="text-3xl font-extrabold tracking-tight text-gray-900">Admin Request</h1>
              <p className="text-gray-600 mt-1 text-sm">
                Submit your request and wait for admin approval.
              </p>
            </div>
            <Badge
              variant="secondary"
              className={
                request?.status === 'approved'
                  ? 'bg-emerald-500/10 text-emerald-700 border-none px-4 py-1 rounded-full font-bold text-[10px] uppercase tracking-widest'
                  : request?.status === 'pending'
                  ? 'bg-blue-500/10 text-blue-700 border-none px-4 py-1 rounded-full font-bold text-[10px] uppercase tracking-widest'
                  : request?.status === 'rejected'
                  ? 'bg-red-500/10 text-red-700 border-none px-4 py-1 rounded-full font-bold text-[10px] uppercase tracking-widest'
                  : 'bg-gray-500/10 text-gray-700 border-none px-4 py-1 rounded-full font-bold text-[10px] uppercase tracking-widest'
              }
            >
              {statusLabel}
            </Badge>
          </div>

          {error && (
            <div className="bg-red-50 text-red-700 border border-red-200 rounded-2xl px-4 py-3 text-sm">
              {error}
            </div>
          )}

          {loadingRequest && (
            <div className="text-sm text-gray-500">Checking your request...</div>
          )}

          {request?.status === 'approved' ? (
            <div className="bg-emerald-500/5 border border-emerald-500/10 rounded-2xl px-4 py-4 text-sm text-emerald-700">
              Your request is approved. You can access the admin dashboard.
              <div className="mt-4">
                <Button
                  render={<Link href="/admin" />}
                  className="rounded-2xl px-6"
                  disabled={false}
                >
                  Go to Admin Dashboard
                </Button>
              </div>
            </div>
          ) : (
            <div className="space-y-3">
              <div className="text-sm text-gray-600">
                {request?.status === 'pending' ? (
                  <>
                    We received your request{request.requested_at ? ` at ${new Date(request.requested_at).toLocaleString()}` : ''}.
                  </>
                ) : request?.status === 'rejected' ? (
                  <>Your request was rejected. Please submit again.</>
                ) : (
                  <>You have not requested admin access yet.</>
                )}
              </div>

              <div className="flex gap-3 flex-wrap">
                <Button
                  onClick={handleRequestAdmin}
                  disabled={loadingRequest || request?.status === 'pending'}
                  className="rounded-2xl px-8 h-12 font-black shadow-xl shadow-primary/20"
                >
                  {loadingRequest
                    ? 'Sending...'
                    : request?.status === 'pending'
                    ? 'Pending...'
                    : 'Request Admin Access'}
                </Button>

                {request?.status === 'pending' && (
                  <Button
                    variant="outline"
                    disabled
                    className="rounded-2xl px-8 h-12 font-bold border-gray-200/70"
                  >
                    Waiting for approval
                  </Button>
                )}
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

'use client';

import { useEffect, useState, useRef, Suspense } from 'react';
import io from 'socket.io-client';
import type { Socket } from 'socket.io-client';
import { useSearchParams } from 'next/navigation';
import { 
  Send, 
  Search, 
  MoreVertical, 
  Phone, 
  Video, 
  Image as ImageIcon, 
  Smile, 
  Paperclip,
  ChevronLeft,
  MessageSquare,
  User as UserIcon,
  Circle
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { Message, User } from '../../types';
import { fetcher } from '../../utils/api';
import { Button } from '../../components/ui/button';
import { Input } from '../../components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '../../components/ui/avatar';
import { Card, CardContent } from '../../components/ui/card';
import { Separator } from '../../components/ui/separator';
import { ScrollArea } from '../../components/ui/scroll-area';
import { Badge } from '../../components/ui/badge';
import { toast } from 'sonner';

const SOCKET_URL = process.env.NEXT_PUBLIC_SOCKET_URL || 'http://localhost:5000';

const ChatContent = () => {
  const { user } = useAuth();
  const searchParams = useSearchParams();
  const [conversations, setConversations] = useState<any[]>([]);
  const [activeChat, setActiveChat] = useState<any>(null);
  const activeChatRef = useRef<any>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const socketRef = useRef<Socket | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    activeChatRef.current = activeChat;
  }, [activeChat]);

  // Initial data load and handle URL params
  useEffect(() => {
    if (!user) return;

    const loadInitialData = async () => {
      try {
        const convList = await fetcher('/chat/list');
        setConversations(convList);

        const otherUserId = searchParams.get('otherUserId');
        const listingId = searchParams.get('listingId');

        if (otherUserId && listingId) {
          // Check if conversation already exists in list
          const existingConv = convList.find(
            (c: any) => 
              (c.senderId === otherUserId || c.receiverId === otherUserId) && 
              c.listingId === Number(listingId)
          );

          if (existingConv) {
            const otherUser = existingConv.senderId === user.id ? existingConv.receiver : existingConv.sender;
            setActiveChat({ otherUser, listing: existingConv.listing });
          } else {
            // New conversation - fetch basic info
            try {
              const listing = await fetcher(`/listings/${listingId}`);
              setActiveChat({ otherUser: listing.user, listing });
            } catch (err) {
              console.error('Failed to load listing for chat:', err);
            }
          }
        }
      } catch (err) {
        console.error('Failed to fetch conversations:', err);
        toast.error('Чат жагсаалтыг ачаалахад алдаа гарлаа');
      }
    };

    loadInitialData();

    // Initialize socket
    socketRef.current = io(SOCKET_URL);

    socketRef.current.on('receive_message', (data: Message) => {
      const currentActiveChat = activeChatRef.current;
      if (currentActiveChat && (data.senderId === currentActiveChat.otherUser.id || data.receiverId === currentActiveChat.otherUser.id)) {
        setMessages((prev) => [...prev, data]);
      }
      
      // Refresh conversations list to show latest message
      fetcher('/chat/list').then(setConversations);
    });

    return () => {
      socketRef.current?.disconnect();
    };
  }, [user, searchParams]);

  useEffect(() => {
    if (activeChat && user) {
      // Join socket room
      const roomId = [user.id, activeChat.otherUser.id].sort().join('-');
      socketRef.current?.emit('join_room', roomId);

      // Fetch message history
      fetcher(`/chat?otherUserId=${activeChat.otherUser.id}&listingId=${activeChat.listing.id}`)
        .then(setMessages)
        .catch(err => {
          console.error('Failed to fetch messages:', err);
          toast.error('Зурвасуудыг ачаалахад алдаа гарлаа');
        });
    }
  }, [activeChat, user]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() || !activeChat || !user) return;

    const messageData = {
      text: newMessage,
      receiverId: activeChat.otherUser.id,
      listingId: activeChat.listing.id,
    };

    try {
      const data = await fetcher('/chat', {
        method: 'POST',
        body: JSON.stringify(messageData),
      });

      const roomId = [user.id, activeChat.otherUser.id].sort().join('-');
      socketRef.current?.emit('send_message', { ...data, roomId });
      
      setMessages((prev) => [...prev, data]);
      setNewMessage('');
      
      // Refresh conversations list
      fetcher('/chat/list').then(setConversations);
    } catch (err) {
      console.error(err);
      toast.error('Зурвас илгээхэд алдаа гарлаа');
    }
  };

  const filteredConversations = conversations.filter(conv => {
    const otherUser = conv.senderId === user?.id ? conv.receiver : conv.sender;
    return (
      otherUser.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      conv.listing.title.toLowerCase().includes(searchQuery.toLowerCase())
    );
  });

  if (!user) return (
    <div className="min-h-[60vh] flex flex-col items-center justify-center text-center space-y-4">
      <div className="w-20 h-20 rounded-full bg-muted flex items-center justify-center">
        <UserIcon className="h-10 w-10 text-muted-foreground" />
      </div>
      <h1 className="text-2xl font-bold">Нэвтрэх шаардлагатай</h1>
      <p className="text-muted-foreground">Чат бичихийн тулд эхлээд нэвтэрнэ үү.</p>
      <Button render={<a href="/login" />}>Нэвтрэх</Button>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto h-[calc(100vh-140px)] min-h-[600px] flex gap-6 p-4 md:p-6 overflow-hidden">
      {/* Sidebar: Conversations */}
      <Card className={`w-full md:w-[380px] flex flex-col rounded-[2.5rem] border-none shadow-2xl overflow-hidden bg-card transition-all duration-300 ${activeChat ? 'hidden md:flex' : 'flex'}`}>
        <div className="p-6 space-y-6">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-black tracking-tight">Чат</h1>
            <Button variant="ghost" size="icon" className="rounded-full">
              <MoreVertical className="h-5 w-5" />
            </Button>
          </div>
          
          <div className="relative group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground transition-colors group-focus-within:text-primary" />
            <Input 
              placeholder="Хайх..." 
              className="pl-11 h-12 rounded-2xl border-none bg-muted/50 focus-visible:ring-primary/20"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>
        </div>

        <ScrollArea className="flex-grow px-3">
          <div className="space-y-2 pb-6">
            {filteredConversations.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center space-y-4 px-6">
                <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center">
                  <MessageSquare className="h-8 w-8 text-muted-foreground/50" />
                </div>
                <p className="text-muted-foreground text-sm">Одоогоор чат байхгүй байна.</p>
              </div>
            ) : (
              filteredConversations.map((conv, idx) => {
                const otherUser = conv.senderId === user.id ? conv.receiver : conv.sender;
                const isActive = activeChat?.otherUser?.id === otherUser.id && activeChat?.listing?.id === conv.listing.id;
                
                return (
                  <button
                    key={idx}
                    onClick={() => setActiveChat({ otherUser, listing: conv.listing })}
                    className={`w-full p-4 rounded-3xl flex items-center gap-4 transition-all duration-300 group ${
                      isActive 
                        ? 'bg-primary text-primary-foreground shadow-xl shadow-primary/20' 
                        : 'hover:bg-muted/50'
                    }`}
                  >
                    <div className="relative shrink-0">
                      <Avatar className="h-14 w-14 border-2 border-background shadow-sm">
                        <AvatarImage src={otherUser.avatar} className="object-cover" />
                        <AvatarFallback className={isActive ? 'bg-white/20 text-white' : 'bg-primary/5 text-primary'}>
                          {otherUser.name.charAt(0)}
                        </AvatarFallback>
                      </Avatar>
                      <Circle className={`absolute bottom-0 right-0 h-4 w-4 fill-emerald-500 stroke-background stroke-2 ${isActive ? 'hidden' : 'block'}`} />
                    </div>
                    
                    <div className="flex-grow overflow-hidden text-left">
                      <div className="flex items-center justify-between gap-2 mb-1">
                        <span className="font-bold truncate">{otherUser.name}</span>
                        <span className={`text-[10px] whitespace-nowrap opacity-60 ${isActive ? 'text-primary-foreground' : ''}`}>
                          {new Date(conv.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                      </div>
                      <div className={`text-xs font-medium truncate mb-1 ${isActive ? 'text-primary-foreground/80' : 'text-primary'}`}>
                        {conv.listing.title}
                      </div>
                      <div className={`text-sm truncate opacity-70 ${isActive ? 'text-primary-foreground/90' : 'text-muted-foreground'}`}>
                        {conv.text}
                      </div>
                    </div>
                  </button>
                );
              })
            )}
          </div>
        </ScrollArea>
      </Card>

      {/* Main: Chat Window */}
      <Card className={`flex-grow flex flex-col rounded-[2.5rem] border-none shadow-2xl overflow-hidden bg-card transition-all duration-300 ${activeChat ? 'flex' : 'hidden md:flex'}`}>
        {activeChat ? (
          <>
            {/* Header */}
            <div className="p-6 flex items-center justify-between bg-card border-b border-border/50">
              <div className="flex items-center gap-4">
                <Button variant="ghost" size="icon" className="md:hidden rounded-full" onClick={() => setActiveChat(null)}>
                  <ChevronLeft className="h-6 w-6" />
                </Button>
                <div className="relative">
                  <Avatar className="h-12 w-12 border-2 border-primary/10 p-0.5">
                    <AvatarImage src={activeChat.otherUser?.avatar} className="rounded-full object-cover" />
                    <AvatarFallback className="bg-primary/5 text-primary">{activeChat.otherUser?.name?.charAt(0)}</AvatarFallback>
                  </Avatar>
                  <Circle className="absolute bottom-0 right-0 h-3.5 w-3.5 fill-emerald-500 stroke-background stroke-2" />
                </div>
                <div>
                  <div className="font-bold text-lg leading-tight">{activeChat.otherUser?.name}</div>
                  <div className="text-xs text-primary font-medium flex items-center gap-1">
                    {activeChat.listing?.title}
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-1">
                <Button variant="ghost" size="icon" className="rounded-full text-muted-foreground hover:text-primary">
                  <Phone className="h-5 w-5" />
                </Button>
                <Button variant="ghost" size="icon" className="rounded-full text-muted-foreground hover:text-primary">
                  <Video className="h-5 w-5" />
                </Button>
                <Button variant="ghost" size="icon" className="rounded-full text-muted-foreground hover:text-primary">
                  <MoreVertical className="h-5 w-5" />
                </Button>
              </div>
            </div>

            {/* Messages */}
            <ScrollArea className="flex-grow bg-muted/20">
              <div className="p-6 space-y-6">
                <div className="flex justify-center">
                  <Badge variant="outline" className="bg-background/50 backdrop-blur-sm border-border/50 text-[10px] px-4 py-1 rounded-full uppercase tracking-widest font-bold text-muted-foreground">
                    Today
                  </Badge>
                </div>

                {messages.map((msg, idx) => {
                  const isOwn = msg.senderId === user.id;
                  return (
                    <div
                      key={msg.id || idx}
                      className={`flex ${isOwn ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
                    >
                      <div className={`flex flex-col gap-1.5 max-w-[80%] md:max-w-[70%] ${isOwn ? 'items-end' : 'items-start'}`}>
                        <div
                          className={`px-5 py-3.5 rounded-[2rem] text-sm shadow-sm transition-all hover:shadow-md ${
                            isOwn
                              ? 'bg-primary text-primary-foreground rounded-tr-none'
                              : 'bg-background text-foreground border border-border/50 rounded-tl-none'
                          }`}
                        >
                          {msg.text}
                        </div>
                        <span className="text-[10px] font-bold text-muted-foreground/60 px-2 uppercase tracking-tighter">
                          {new Date(msg.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                      </div>
                    </div>
                  );
                })}
                <div ref={messagesEndRef} />
              </div>
            </ScrollArea>

            {/* Input */}
            <div className="p-6 bg-card border-t border-border/50">
              <form onSubmit={handleSendMessage} className="flex items-center gap-3">
                <div className="flex items-center gap-1">
                  <Button type="button" variant="ghost" size="icon" className="rounded-full text-muted-foreground hover:text-primary">
                    <Paperclip className="h-5 w-5" />
                  </Button>
                  <Button type="button" variant="ghost" size="icon" className="rounded-full text-muted-foreground hover:text-primary">
                    <ImageIcon className="h-5 w-5" />
                  </Button>
                </div>
                
                <div className="relative flex-grow group">
                  <Input
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    placeholder="Зурвас бичих..."
                    className="h-14 rounded-[2rem] border-none bg-muted/50 pl-6 pr-14 text-md focus-visible:ring-primary/20 transition-all"
                  />
                  <Button 
                    type="button" 
                    variant="ghost" 
                    size="icon" 
                    className="absolute right-2 top-1/2 -translate-y-1/2 rounded-full text-muted-foreground hover:text-primary"
                  >
                    <Smile className="h-5 w-5" />
                  </Button>
                </div>
                
                <Button
                  type="submit"
                  disabled={!newMessage.trim()}
                  className="h-14 w-14 rounded-full bg-primary shadow-xl shadow-primary/20 hover:scale-105 transition-transform"
                >
                  <Send className="h-6 w-6 fill-primary-foreground" />
                </Button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-grow flex flex-col items-center justify-center text-center p-10 space-y-6">
            <div className="w-32 h-32 rounded-full bg-primary/5 flex items-center justify-center animate-pulse">
              <MessageSquare className="h-16 w-16 text-primary/20" />
            </div>
            <div className="space-y-2 max-w-sm">
              <h2 className="text-2xl font-black tracking-tight">Таны зурвасууд</h2>
              <p className="text-muted-foreground">
                Худалдагч эсвэл худалдан авагчтайгаа холбогдож барааныхаа талаар ярилцаарай.
              </p>
            </div>
            <Button variant="outline" className="rounded-full px-8 h-12 font-bold border-2 md:hidden" onClick={() => setActiveChat(null)}>
              Харилцаа сонгох
            </Button>
          </div>
        )}
      </Card>
    </div>
  );
};

const ChatPage = () => {
  return (
    <Suspense fallback={<div className="p-10 text-center">Ачаалж байна...</div>}>
      <ChatContent />
    </Suspense>
  );
};

export default ChatPage;

'use client';

import { useState, useRef, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { 
  Camera, 
  MapPin, 
  Tag, 
  DollarSign, 
  Info, 
  CheckCircle2, 
  ChevronRight, 
  ChevronLeft,
  Image as ImageIcon,
  X,
  Plus,
  Upload,
  Loader2
} from 'lucide-react';
import { Category } from '../../types';
import { fetcher } from '../../utils/api';
import { supabase } from '../../utils/supabase';
import { useAuth } from '../../context/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from '@/components/ui/select';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { toast } from 'sonner';

const CreateListingPage = () => {
  const { user } = useAuth();
  const router = useRouter();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    category: Category.ELECTRONICS,
    location: '',
    imageUrl: '',
  });

  useEffect(() => {
    if (!user) {
      router.push('/login');
    }
  }, [user, router]);

  if (!user) {
    return null;
  }

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Check file size (limit to 5MB)
    if (file.size > 5 * 1024 * 1024) {
      toast.error('Зургийн хэмжээ 5MB-аас бага байх ёстой');
      return;
    }

    setUploading(true);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const filePath = `${user.id}/${fileName}`;

      const { error: uploadError, data } = await supabase.storage
        .from('listings')
        .upload(filePath, file);

      if (uploadError) {
        throw uploadError;
      }

      const { data: { publicUrl } } = supabase.storage
        .from('listings')
        .getPublicUrl(filePath);

      setFormData({ ...formData, imageUrl: publicUrl });
      toast.success('Зураг амжилттай хуулагдлаа');
    } catch (error: any) {
      console.error('Error uploading image:', error);
      toast.error('Зураг хуулахад алдаа гарлаа: ' + error.message);
    } finally {
      setUploading(false);
    }
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    if (step < 3) {
      setStep(step + 1);
      return;
    }

    if (!formData.imageUrl) {
      toast.error('Ямар нэгэн зураг оруулна уу');
      setStep(2);
      return;
    }

    setLoading(true);
    try {
      const { imageUrl, ...rest } = formData;
      const data = await fetcher('/listings', {
        method: 'POST',
        body: JSON.stringify({
          ...rest,
          price: Number(formData.price),
          images: imageUrl ? [imageUrl] : [],
          userId: user.id,
        }),
      });
      toast.success('Зарыг амжилттай нийтэллээ!');
      router.push(`/listings/${data.id}`);
    } catch (err) {
      console.error(err);
      toast.error('Зарыг нийтлэхэд алдаа гарлаа');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (name: string, value: string) => {
    setFormData({ ...formData, [name]: value });
  };

  const nextStep = () => setStep((s) => Math.min(s + 1, 3));
  const prevStep = () => setStep((s) => Math.max(s - 1, 1));

  const progress = (step / 3) * 100;

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <div className="mb-10 space-y-4 text-center">
        <h1 className="text-4xl font-black tracking-tight">Шинэ зар оруулах</h1>
        <p className="text-muted-foreground">Мэдээллээ үнэн зөв бөглөж илүү олон хүнд хүргээрэй</p>
        
        <div className="max-w-xs mx-auto space-y-2">
          <div className="flex justify-between text-xs font-bold text-muted-foreground uppercase tracking-widest">
            <span>Алхам {step} / 3</span>
            <span>{Math.round(progress)}% бөглөсөн</span>
          </div>
          <Progress value={progress} className="h-2 rounded-full" />
        </div>
      </div>

      <Card className="rounded-[2.5rem] border-none shadow-2xl overflow-hidden bg-card">
        <CardContent className="p-8 md:p-12">
          <form onSubmit={handleSubmit} className="space-y-8">
            {step === 1 && (
              <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="space-y-4">
                  <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 text-primary text-xs font-bold uppercase tracking-wider">
                    <Info className="h-3 w-3" /> Ерөнхий мэдээлэл
                  </div>
                  <h2 className="text-2xl font-bold">Та юу зарах гэж байна вэ?</h2>
                </div>

                <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-sm font-bold ml-1">Гарчиг</label>
                    <Input
                      name="title"
                      value={formData.title}
                      onChange={(event) => handleChange('title', event.target.value)}
                      placeholder="Жишээ нь: iPhone 15 Pro Max 256GB..."
                      className="h-14 rounded-2xl border-2 focus-visible:ring-primary/20 text-lg px-6"
                      required
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <label className="text-sm font-bold ml-1">Ангилал</label>
                      <Select 
                        value={formData.category} 
                        onValueChange={(val) => val && handleChange('category', val)}
                      >
                        <SelectTrigger className="h-14 rounded-2xl border-2 px-6 text-lg">
                          <SelectValue placeholder="Ангилал сонгох" />
                        </SelectTrigger>
                        <SelectContent className="rounded-2xl">
                          {Object.values(Category).map((cat) => (
                            <SelectItem key={cat} value={cat} className="rounded-xl py-3">
                              {cat.replace('_', ' ')}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>

                    <div className="space-y-2">
                      <label className="text-sm font-bold ml-1">Үнэ (₮)</label>
                      <div className="relative">
                        <Input
                          type="number"
                          name="price"
                          value={formData.price}
                          onChange={(event) => handleChange('price', event.target.value)}
                          placeholder="0.00"
                          className="h-14 rounded-2xl border-2 pl-12 pr-6 text-lg"
                          required
                        />
                        <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
                <div className="space-y-4">
                  <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 text-primary text-xs font-bold uppercase tracking-wider">
                    <Camera className="h-3 w-3" /> Зураг & Байршил
                  </div>
                  <h2 className="text-2xl font-bold">Зураг болон байршил нэмэх</h2>
                </div>

                <div className="space-y-8">
                  <div className="space-y-4">
                    <label className="text-sm font-bold ml-1">Зураг оруулах</label>
                    <div className="grid grid-cols-1 gap-4">
                      {formData.imageUrl ? (
                        <div className="relative aspect-video rounded-3xl overflow-hidden group">
                          <img src={formData.imageUrl} alt="Preview" className="w-full h-full object-cover" />
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                            <Button 
                              type="button" 
                              variant="destructive" 
                              size="icon" 
                              className="rounded-full"
                              onClick={() => setFormData({ ...formData, imageUrl: '' })}
                            >
                              <X className="h-5 w-5" />
                            </Button>
                          </div>
                        </div>
                      ) : (
                        <div 
                          onClick={() => !uploading && fileInputRef.current?.click()}
                          className={`aspect-video rounded-3xl border-4 border-dashed border-muted hover:border-primary/50 hover:bg-primary/5 transition-all flex flex-col items-center justify-center gap-4 cursor-pointer group ${uploading ? 'opacity-50 cursor-not-allowed' : ''}`}
                        >
                          <input 
                            type="file" 
                            ref={fileInputRef} 
                            onChange={handleFileUpload} 
                            accept="image/*" 
                            className="hidden" 
                          />
                          <div className="h-16 w-16 rounded-full bg-muted flex items-center justify-center group-hover:scale-110 transition-transform">
                            {uploading ? (
                              <Loader2 className="h-8 w-8 text-primary animate-spin" />
                            ) : (
                              <Upload className="h-8 w-8 text-muted-foreground" />
                            )}
                          </div>
                          <div className="text-center px-4">
                            <p className="font-bold text-lg">Зураг сонгох</p>
                            <p className="text-sm text-muted-foreground mt-1">
                              {uploading ? 'Түр хүлээнэ үү...' : 'Компьютер эсвэл утаснаасаа зураг сонгоно уу'}
                            </p>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-bold ml-1">Байршил</label>
                    <div className="relative">
                      <Input
                        name="location"
                        value={formData.location}
                        onChange={(event) => handleChange('location', event.target.value)}
                        placeholder="Жишээ нь: Улаанбаатар, Баянзүрх дүүрэг..."
                        className="h-14 rounded-2xl border-2 pl-12 pr-6 text-lg"
                        required
                      />
                      <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                    </div>
                  </div>
                </div>
              </div>
            )}

            {step === 3 && (
              <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-500">
                <div className="space-y-4">
                  <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 text-primary text-xs font-bold uppercase tracking-wider">
                    <CheckCircle2 className="h-3 w-3" /> Эцсийн алхам
                  </div>
                  <h2 className="text-2xl font-bold">Дэлгэрэнгүй тайлбар оруулна уу</h2>
                </div>

                <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-sm font-bold ml-1">Тайлбар</label>
                    <Textarea
                      name="description"
                      value={formData.description}
                      onChange={(event) => handleChange('description', event.target.value)}
                      placeholder="Барааныхаа давуу тал, төлөв байдал зэргийг дэлгэрэнгүй бичээрэй..."
                      className="min-h-[250px] rounded-3xl border-2 p-6 text-lg focus-visible:ring-primary/20 resize-none"
                      required
                    />
                  </div>

                  <div className="p-6 rounded-3xl bg-emerald-500/5 border border-emerald-500/10 flex gap-4">
                    <div className="h-10 w-10 rounded-full bg-emerald-500/10 flex items-center justify-center shrink-0">
                      <CheckCircle2 className="h-6 w-6 text-emerald-600" />
                    </div>
                    <div className="space-y-1">
                      <p className="font-bold text-emerald-900">Бүх зүйл бэлэн!</p>
                      <p className="text-sm text-emerald-700/80">Мэдээллээ шалгаад "Нийтлэх" товчийг дарж зарыг идэвхжүүлнэ үү.</p>
                    </div>
                  </div>
                </div>
              </div>
            )}

            <div className="flex gap-4 pt-6">
              {step > 1 && (
                <Button
                  type="button"
                  variant="outline"
                  size="xl"
                  onClick={prevStep}
                  className="flex-1 rounded-2xl h-16 text-lg font-bold border-2"
                >
                  <ChevronLeft className="h-5 w-5 mr-2" /> Буцах
                </Button>
              )}
              <Button
                type="submit"
                disabled={loading}
                size="xl"
                className={`flex-[2] rounded-2xl h-16 text-lg font-bold shadow-xl transition-all ${
                  step === 3 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'shadow-primary/20'
                }`}
              >
                {loading ? (
                  'Түр хүлээнэ үү...'
                ) : step === 3 ? (
                  'Нийтлэх'
                ) : (
                  <>
                    Үргэлжлүүлэх <ChevronRight className="h-5 w-5 ml-2" />
                  </>
                )}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
};

export default CreateListingPage;

'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { 
  MapPin, 
  Calendar, 
  Tag, 
  MessageCircle, 
  Phone, 
  ShieldCheck, 
  Flag, 
  Share2, 
  Heart,
  ChevronLeft,
  ChevronRight,
  CheckCircle2,
  Clock,
  Info
} from 'lucide-react';
import { Listing } from '../../../types';
import { fetcher } from '../../../utils/api';
import { useAuth } from '../../../context/AuthContext';
import { Button } from '../../../components/ui/button';
import { Badge } from '../../../components/ui/badge';
import { Card, CardContent } from '../../../components/ui/card';
import { Avatar, AvatarFallback, AvatarImage } from '../../../components/ui/avatar';
import { Separator } from '../../../components/ui/separator';
import { Skeleton } from '../../../components/ui/skeleton';
import { toast } from 'sonner';

const ListingDetailPage = () => {
  const { id } = useParams();
  const router = useRouter();
  const { user: currentUser } = useAuth();
  const [listing, setListing] = useState<Listing | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeImageIdx, setActiveImageIdx] = useState(0);

  useEffect(() => {
    const loadListing = async () => {
      try {
        const data = await fetcher(`/listings/${id}`);
        setListing(data);
      } catch (error) {
        console.error('Failed to fetch listing:', error);
        toast.error('Зарыг ачаалахад алдаа гарлаа');
      } finally {
        setLoading(false);
      }
    };
    if (id) loadListing();
  }, [id]);

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto py-10 space-y-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
          <div className="lg:col-span-2 space-y-6">
            <Skeleton className="aspect-[16/9] w-full rounded-3xl" />
            <div className="space-y-4">
              <Skeleton className="h-10 w-3/4" />
              <Skeleton className="h-6 w-1/2" />
              <Skeleton className="h-32 w-full" />
            </div>
          </div>
          <div className="space-y-6">
            <Skeleton className="h-64 w-full rounded-3xl" />
            <Skeleton className="h-40 w-full rounded-3xl" />
          </div>
        </div>
      </div>
    );
  }

  if (!listing) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center text-center space-y-4">
        <div className="w-20 h-20 rounded-full bg-muted flex items-center justify-center">
          <Info className="h-10 w-10 text-muted-foreground" />
        </div>
        <h1 className="text-2xl font-bold">Зар олдсонгүй</h1>
        <p className="text-muted-foreground">Уучлаарай, таны хайсан зар устгагдсан эсвэл байхгүй байна.</p>
        <Button onClick={() => router.push('/')}>Нүүр хуудас руу буцах</Button>
      </div>
    );
  }

  const formattedPrice = new Intl.NumberFormat('mn-MN', {
    style: 'currency',
    currency: 'MNT',
    maximumFractionDigits: 0,
  }).format(listing.price);

  const nextImage = () => {
    setActiveImageIdx((prev) => (prev + 1) % listing.images.length);
  };

  const prevImage = () => {
    setActiveImageIdx((prev) => (prev - 1 + listing.images.length) % listing.images.length);
  };

  const handleChatClick = () => {
    if (!currentUser) {
      toast.error('Чат бичихийн тулд нэвтрэх шаардлагатай');
      router.push('/login');
      return;
    }
    router.push(`/chat?otherUserId=${listing.user?.id}&listingId=${listing.id}`);
  };

  return (
    <div className="max-w-7xl mx-auto py-6 md:py-10 space-y-8 px-4">
      {/* Breadcrumbs & Actions */}
      <div className="flex items-center justify-between">
        <Button variant="ghost" size="sm" onClick={() => router.back()} className="rounded-full">
          <ChevronLeft className="h-4 w-4 mr-1" /> Буцах
        </Button>
        <div className="flex items-center gap-2">
          <Button variant="outline" size="icon" className="rounded-full h-10 w-10">
            <Share2 className="h-4 w-4" />
          </Button>
          <Button variant="outline" size="icon" className="rounded-full h-10 w-10">
            <Heart className="h-4 w-4" />
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 items-start">
        {/* Left: Gallery & Content */}
        <div className="lg:col-span-2 space-y-8">
          {/* Gallery */}
          <div className="group relative bg-muted rounded-[2.5rem] overflow-hidden shadow-2xl">
            <div className="aspect-[16/9] relative overflow-hidden">
              <img 
                src={listing.images[activeImageIdx] || 'https://images.unsplash.com/photo-1580587771525-78b9dba3b914?auto=format&fit=crop&q=80&w=1200'} 
                alt={listing.title} 
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" 
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent" />
              
              {listing.images.length > 1 && (
                <>
                  <Button 
                    variant="secondary" 
                    size="icon" 
                    className="absolute left-4 top-1/2 -translate-y-1/2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity bg-white/80 backdrop-blur-md"
                    onClick={prevImage}
                  >
                    <ChevronLeft className="h-6 w-6" />
                  </Button>
                  <Button 
                    variant="secondary" 
                    size="icon" 
                    className="absolute right-4 top-1/2 -translate-y-1/2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity bg-white/80 backdrop-blur-md"
                    onClick={nextImage}
                  >
                    <ChevronRight className="h-6 w-6" />
                  </Button>
                  
                  <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2">
                    {listing.images.map((_, idx) => (
                      <div 
                        key={idx} 
                        className={`h-1.5 rounded-full transition-all duration-300 ${activeImageIdx === idx ? 'w-8 bg-white' : 'w-2 bg-white/40'}`}
                      />
                    ))}
                  </div>
                </>
              )}
            </div>

            {listing.images.length > 1 && (
              <div className="flex gap-4 p-6 overflow-x-auto scrollbar-hide bg-background/50 backdrop-blur-xl border-t border-white/10">
                {listing.images.map((img, idx) => (
                  <button
                    key={idx}
                    onClick={() => setActiveImageIdx(idx)}
                    className={`flex-shrink-0 w-24 h-16 rounded-xl overflow-hidden border-2 transition-all duration-300 hover:scale-105 ${
                      activeImageIdx === idx ? 'border-primary ring-2 ring-primary/20 scale-105' : 'border-transparent opacity-60 hover:opacity-100'
                    }`}
                  >
                    <img src={img} className="w-full h-full object-cover" alt="" />
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Details */}
          <div className="bg-card border border-border/50 p-8 md:p-10 rounded-[2.5rem] shadow-sm space-y-8">
            <div className="space-y-4">
              <div className="flex flex-wrap gap-2">
                <Badge variant="secondary" className="rounded-lg px-3 py-1 font-semibold uppercase tracking-wider text-[10px]">
                  {listing.category}
                </Badge>
                <Badge variant="outline" className="rounded-lg px-3 py-1 font-semibold text-[10px] flex items-center gap-1 border-emerald-500/20 text-emerald-600 bg-emerald-500/5">
                  <Clock className="h-3 w-3" /> {new Date(listing.createdAt).toLocaleDateString('mn-MN')}
                </Badge>
              </div>
              <h1 className="text-3xl md:text-5xl font-extrabold tracking-tight leading-tight">{listing.title}</h1>
              <div className="flex items-center text-muted-foreground gap-2 font-medium">
                <MapPin className="h-5 w-5 text-primary" />
                <span>{listing.location}</span>
              </div>
            </div>

            <Separator />

            <div className="space-y-6">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                Тайлбар
              </h2>
              <p className="text-muted-foreground text-lg leading-relaxed whitespace-pre-wrap">
                {listing.description}
              </p>
            </div>

            <Separator />

            <div className="flex items-center justify-between">
              <Button variant="ghost" size="sm" className="text-muted-foreground hover:text-red-500 transition-colors">
                <Flag className="h-4 w-4 mr-2" /> Зарын тухай мэдээлэх
              </Button>
              <span className="text-xs text-muted-foreground">Зарын ID: {listing.id}</span>
            </div>
          </div>
        </div>

        {/* Right: Price & Seller Card */}
        <div className="space-y-8 lg:sticky lg:top-24">
          <Card className="rounded-[2.5rem] border-none shadow-2xl bg-primary text-primary-foreground overflow-hidden relative">
            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl" />
            <div className="absolute bottom-0 left-0 w-32 h-32 bg-black/10 rounded-full -ml-16 -mb-16 blur-3xl" />
            
            <CardContent className="p-8 space-y-6 relative z-10">
              <div className="space-y-1">
                <p className="text-primary-foreground/70 font-medium text-sm">Нийт үнэ</p>
                <div className="text-3xl md:text-4xl font-black tracking-tighter">
                  {formattedPrice}
                </div>
              </div>
              
              <div className="grid gap-3">
                <Button 
                  size="xl" 
                  className="w-full rounded-2xl bg-white text-primary hover:bg-white/90 font-bold text-lg h-14 shadow-xl"
                  onClick={handleChatClick}
                >
                  <MessageCircle className="h-5 w-5 mr-2 fill-primary" /> Чат бичих
                </Button>
                <Button 
                  size="xl" 
                  variant="outline" 
                  className="w-full rounded-2xl border-white/20 bg-white/10 hover:bg-white/20 text-white font-bold text-lg h-14 backdrop-blur-md"
                  render={listing.user?.phone ? <a href={`tel:${listing.user.phone}`} /> : undefined}
                >
                  <Phone className="h-5 w-5 mr-2" /> {listing.user?.phone || 'Утас харах'}
                </Button>
              </div>
            </CardContent>
          </Card>

          <Card className="rounded-[2.5rem] border border-border/50 shadow-sm overflow-hidden bg-card">
            <CardContent className="p-8 space-y-6">
              <div className="flex items-center gap-4">
                <Avatar className="h-16 w-16 border-2 border-primary/10 p-1">
                  <AvatarImage src={listing.user?.avatar} className="rounded-full object-cover" />
                  <AvatarFallback className="text-xl bg-primary/5 text-primary">{listing.user?.name?.charAt(0)}</AvatarFallback>
                </Avatar>
                <div>
                  <div className="font-bold text-xl flex items-center gap-2">
                    {listing.user?.name}
                    {listing.user?.isVerified && (
                      <CheckCircle2 className="h-5 w-5 text-blue-500" />
                    )}
                  </div>
                  <p className="text-sm text-muted-foreground font-medium">
                    {new Date(listing.user?.createdAt || '').getFullYear()} оноос хойш гишүүн
                  </p>
                </div>
              </div>

              <Separator />

              <div className="space-y-4">
                <div className="flex items-center gap-3 text-sm font-medium p-4 rounded-2xl bg-muted/50 border border-border/50">
                  <ShieldCheck className="h-5 w-5 text-emerald-500 shrink-0" />
                  <div className="space-y-0.5">
                    <p className="font-bold">Аюулгүй байдлын зөвлөгөө</p>
                    <p className="text-xs text-muted-foreground">Урьдчилгаа төлбөр хийхгүй байхыг зөвлөж байна.</p>
                  </div>
                </div>
              </div>

              <Button variant="link" className="w-full font-bold text-primary p-0 h-auto" onClick={() => router.push(`/profile/${listing.user?.id}`)}>
                Хэрэглэгчийн бусад зарууд
              </Button>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
};

export default ListingDetailPage;

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { 
  Search, 
  Home as HomeIcon, 
  Car, 
  Laptop, 
  Briefcase, 
  Wrench, 
  ChevronRight,
  Sparkles,
  ArrowRight,
  Bot,
  Loader2,
  X
} from 'lucide-react';
import ListingCard from '../components/ListingCard';
import { Listing, Category } from '../types';
import { fetcher } from '../utils/api';
import { Button } from '../components/ui/button';
import { Input } from '../components/ui/input';
import { Skeleton } from '../components/ui/skeleton';
import { Badge } from '../components/ui/badge';
import { toast } from 'sonner';

const categories = [
  { name: 'Үл хөдлөх', icon: HomeIcon, value: Category.REAL_ESTATE, color: 'bg-blue-500/10 text-blue-600' },
  { name: 'Автомашин', icon: Car, value: Category.CARS, color: 'bg-orange-500/10 text-orange-600' },
  { name: 'Электроникс', icon: Laptop, value: Category.ELECTRONICS, color: 'bg-purple-500/10 text-purple-600' },
  { name: 'Ажил', icon: Briefcase, value: Category.JOBS, color: 'bg-green-500/10 text-green-600' },
  { name: 'Үйлчилгээ', icon: Wrench, value: Category.SERVICES, color: 'bg-red-500/10 text-red-600' },
];

export default function Home() {
  const [latestListings, setLatestListings] = useState<Listing[]>([]);
  const [recommendedListings, setRecommendedListings] = useState<Listing[]>([]);
  const [loading, setLoading] = useState(true);
  
  // AI Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [isAiMode, setIsAiMode] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResults, setAiResults] = useState<Listing[] | null>(null);
  const [aiFilters, setAiFilters] = useState<any>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const data = await fetcher('/listings?sort=newest');
        setLatestListings(data.slice(0, 8));
        setRecommendedListings(data.slice(0, 4));
      } catch (error) {
        console.error('Failed to fetch listings:', error);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    if (isAiMode) {
      setAiLoading(true);
      setAiResults(null);
      try {
        const data = await fetcher('/ai/search', {
          method: 'POST',
          body: JSON.stringify({ query: searchQuery }),
        });
        setAiResults(data.results);
        setAiFilters(data.filters);
        toast.success('AI хайлт амжилттай боллоо');
      } catch (error: any) {
        console.error('AI Search failed:', error);
        toast.error(error.message || 'AI хайлт хийхэд алдаа гарлаа');
      } finally {
        setAiLoading(false);
      }
    } else {
      // Normal search redirect
      window.location.href = `/listings?search=${encodeURIComponent(searchQuery)}`;
    }
  };

  const clearAiResults = () => {
    setAiResults(null);
    setAiFilters(null);
    setSearchQuery('');
  };

  return (
    <div className="flex flex-col gap-24 pb-20">
      {/* Hero Section */}
      <section className="relative h-[500px] md:h-[600px] rounded-[3rem] overflow-hidden flex items-center px-6 md:px-16 mx-4 mt-4">
        <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1512453979798-5ea266f8880c?q=80&w=2070&auto=format&fit=crop')] bg-cover bg-center" />
        <div className="absolute inset-0 bg-gradient-to-r from-black/80 via-black/40 to-transparent" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent" />

        <div className="relative z-10 w-full max-w-5xl space-y-10">
          <div className="space-y-6">
            <Badge variant="outline" className="bg-white/10 backdrop-blur-md border-white/20 text-white py-2 px-5 rounded-full text-[10px] font-black uppercase tracking-[0.2em]">
              <Sparkles className="h-3.5 w-3.5 mr-2 text-yellow-400 fill-yellow-400" />
              Шинэ үеийн зар сурталчилгааны талбар
            </Badge>

            <h1 className="text-5xl md:text-8xl font-[1000] text-white leading-[0.95] tracking-[-0.04em]">
              Хэрэгцээт бүхнээ <br />
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-emerald-400 to-emerald-300 animate-gradient">
                нэг дороос.
              </span>
            </h1>

            <p className="text-lg md:text-xl text-white/80 font-medium max-w-2xl leading-relaxed">
              Мянга мянган хэрэглэгчдийн итгэлт түнш, Монголын хамгийн том <br className="hidden md:block" />
              зар сурталчилгааны нэгдсэн системд тавтай морил.
            </p>
          </div>

          <div className="relative max-w-2xl group">
            <div className={`absolute -inset-1 bg-gradient-to-r ${isAiMode ? 'from-purple-600 to-blue-600' : 'from-blue-600 to-emerald-600'} rounded-2xl blur opacity-25 group-hover:opacity-40 transition duration-1000 group-hover:duration-200`}></div>
            <form onSubmit={handleSearch} className="relative bg-white/95 dark:bg-zinc-900/95 p-1.5 rounded-2xl shadow-2xl backdrop-blur-xl flex flex-col md:flex-row gap-2 border border-white/20">
              <div className="flex-grow flex items-center px-4">
                {isAiMode ? (
                  <Bot className="h-5 w-5 text-purple-500 mr-3 animate-pulse" />
                ) : (
                  <Search className="h-5 w-5 text-muted-foreground mr-3" />
                )}
                <Input
                  placeholder={isAiMode ? "AI-аас юу ч хамаагүй асуу (Жишээ нь: 2 саяас хямд iPhone 13)" : "Та юу хайж байна вэ?"}
                  className="border-none bg-transparent focus-visible:ring-0 text-lg h-12 px-0"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
              <div className="flex items-center gap-2 p-1">
                <Button 
                  type="button"
                  variant="ghost" 
                  size="icon"
                  onClick={() => setIsAiMode(!isAiMode)}
                  className={`rounded-xl h-12 w-12 transition-all ${isAiMode ? 'bg-purple-500/10 text-purple-600 hover:bg-purple-500/20' : 'text-muted-foreground hover:bg-muted'}`}
                  title={isAiMode ? "AI хайлтыг унтраах" : "AI хайлт ашиглах"}
                >
                  <Sparkles className={`h-5 w-5 ${isAiMode ? 'fill-purple-600' : ''}`} />
                </Button>
                <Button 
                  type="submit"
                  size="lg" 
                  disabled={aiLoading}
                  className={`rounded-xl px-8 h-12 text-md font-bold transition-all shadow-lg ${isAiMode ? 'bg-purple-600 hover:bg-purple-700 shadow-purple-200' : 'bg-primary hover:bg-primary/90 shadow-primary/20'}`}
                >
                  {aiLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : 'Хайх'}
                </Button>
              </div>
            </form>
          </div>
          
          <div className="flex flex-wrap gap-4 text-white/70 text-sm font-medium">
            <span>Түгээмэл:</span>
            {['Орон сууц', 'Приус 30', 'iPhone 15', 'Ажлын байр'].map((tag) => (
              <button key={tag} className="hover:text-white transition-colors underline decoration-white/30 underline-offset-4">
                {tag} 
              </button>
            ))}
          </div>
        </div>
      </section>

      <div className="max-w-[1400px] mx-auto px-4 md:px-8 w-full space-y-32">
        {/* AI Search Results */}
        {aiResults && (
          <section className="animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
              <div className="space-y-2">
                <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-purple-500/10 text-purple-600 text-[10px] font-black uppercase tracking-[0.2em] mb-2">
                  <Bot className="h-3.5 w-3.5" /> AI Хайлтын илэрц
                </div>
                <h2 className="text-4xl md:text-5xl font-[1000] tracking-tighter">Таны хайлттай нийцэх зарууд</h2>
                {aiFilters && (
                  <div className="flex flex-wrap gap-2 mt-4">
                    {aiFilters.category && <Badge variant="secondary" className="bg-purple-50">{aiFilters.category}</Badge>}
                    {aiFilters.search && <Badge variant="secondary" className="bg-purple-50">"{aiFilters.search}"</Badge>}
                    {(aiFilters.minPrice || aiFilters.maxPrice) && (
                      <Badge variant="secondary" className="bg-purple-50">
                        {aiFilters.minPrice ? `${aiFilters.minPrice}₮ - ` : ''}
                        {aiFilters.maxPrice ? `${aiFilters.maxPrice}₮` : 'дээш'}
                      </Badge>
                    )}
                    {aiFilters.location && <Badge variant="secondary" className="bg-purple-50">{aiFilters.location}</Badge>}
                  </div>
                )}
              </div>
              <Button onClick={clearAiResults} variant="ghost" className="rounded-2xl h-12 px-6 font-bold hover:bg-red-50 hover:text-red-500 transition-all">
                <X className="mr-2 h-4 w-4" /> Хайлтыг цэвэрлэх
              </Button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {aiResults.map((listing) => (
                <ListingCard key={listing.id} listing={listing} />
              ))}
              {aiResults.length === 0 && (
                <div className="col-span-full py-32 text-center bg-muted/20 rounded-[3rem] border-2 border-dashed">
                  <div className="inline-flex items-center justify-center w-24 h-24 rounded-full bg-muted mb-6">
                    <Search className="h-12 w-12 text-muted-foreground/30" />
                  </div>
                  <p className="text-muted-foreground text-xl font-medium">Уучлаарай, таны хайлттай нийцэх зар олдсонгүй.</p>
                  <Button onClick={() => setIsAiMode(false)} variant="link" className="mt-4 text-primary font-bold">
                    Энгийн хайлт ашиглах уу?
                  </Button>
                </div>
              )}
            </div>
          </section>
        )}

        {/* Categories Grid */}
        <section>
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
            <div className="space-y-2">
              <h2 className="text-4xl md:text-5xl font-[1000] tracking-tighter">Ангилал</h2>
              <p className="text-muted-foreground font-medium text-lg">Төрөл бүрийн ангиллаар хурдан хайлт хийгээрэй</p>
            </div>
            <Button variant="ghost" className="w-fit group font-black uppercase tracking-widest text-xs h-12 px-6 rounded-2xl border bg-muted/30 hover:bg-muted">
              Бүх ангилал <ChevronRight className="ml-2 h-4 w-4 group-hover:translate-x-1 transition-transform" />
            </Button>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-5 gap-6">
            {categories.map((cat) => (
              <Link
                key={cat.value}
                href={`/listings?category=${cat.value}`}
                className="group relative flex flex-col items-center p-10 rounded-[2.5rem] bg-card border border-border/50 shadow-sm hover:shadow-2xl hover:border-primary/20 hover:-translate-y-2 transition-all duration-500"
              >
                <div className={`mb-6 w-24 h-24 rounded-[2rem] ${cat.color} flex items-center justify-center group-hover:scale-110 transition-transform duration-500 shadow-inner`}>
                  <cat.icon className="h-12 w-12 stroke-[1.5px]" />
                </div>
                <div className="font-black text-xl tracking-tight">{cat.name}</div>
                <div className="mt-3 text-xs font-bold text-primary opacity-0 group-hover:opacity-100 transition-all transform translate-y-2 group-hover:translate-y-0">
                  ЗАР ҮЗЭХ <ArrowRight className="inline h-3 w-3 ml-1" />
                </div>
              </Link>
            ))}
          </div>
        </section>

        {/* Latest Listings */}
        <section>
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
            <div className="space-y-2">
              <h2 className="text-4xl md:text-5xl font-[1000] tracking-tighter">Шинэ зарууд</h2>
              <p className="text-muted-foreground font-medium text-lg">Хамгийн сүүлд нэмэгдсэн шинэ боломжууд</p>
            </div>
            <Button render={<Link href="/listings" className="flex items-center" />} variant="ghost" className="font-black uppercase tracking-widest text-xs h-12 px-6 rounded-2xl border bg-muted/30 hover:bg-muted group">
                Бүх зарыг харах <ArrowRight className="ml-2 h-4 w-4 group-hover:translate-x-1 transition-transform" />
            </Button>
          </div>
          
          {loading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {[1, 2, 3, 4, 5, 6, 7, 8].map((i) => (
                <div key={i} className="space-y-4">
                  <Skeleton className="aspect-[4/3] rounded-[2rem]" />
                  <Skeleton className="h-6 w-3/4" />
                  <Skeleton className="h-4 w-1/2" />
                </div>
              ))}
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
              {latestListings.map((listing) => (
                <ListingCard key={listing.id} listing={listing} />
              ))}
            </div>
          )}
        </section>

        {/* Recommended Listings (Featured Section) */}
        <section className="bg-slate-50 dark:bg-zinc-900/50 -mx-4 md:-mx-8 px-4 md:px-16 py-24 rounded-[4rem] border border-border/50">
          <div className="max-w-7xl mx-auto">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
              <div className="space-y-2">
                <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-emerald-500/10 text-emerald-600 text-[10px] font-black uppercase tracking-[0.2em] mb-2">
                  <Sparkles className="h-3.5 w-3.5" /> Онцлох зарууд
                </div>
                <h2 className="text-4xl md:text-5xl font-[1000] tracking-tighter">Танд санал болгох</h2>
                <p className="text-muted-foreground font-medium text-lg">Таны сонирхолд нийцэх хамгийн шилдэг саналууд</p>
              </div>
              <Button render={<Link href="/listings" />} variant="outline" className="rounded-2xl border-2 hover:bg-background h-12 px-8 font-bold shadow-sm">
                Бүгдийг үзэх
              </Button>
            </div>
            
            {loading ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {[1, 2, 3, 4].map((i) => (
                  <div key={i} className="space-y-4">
                    <Skeleton className="aspect-[4/3] rounded-[2rem]" />
                    <Skeleton className="h-6 w-3/4" />
                    <Skeleton className="h-4 w-1/2" />
                  </div>
                ))}
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {recommendedListings.map((listing) => (
                  <ListingCard key={listing.id} listing={listing} />
                ))}
                {recommendedListings.length === 0 && (
                  <div className="col-span-full py-20 text-center">
                    <div className="inline-flex items-center justify-center w-24 h-24 rounded-full bg-muted mb-6">
                      <Search className="h-12 w-12 text-muted-foreground/30" />
                    </div>
                    <p className="text-muted-foreground text-xl font-medium">Одоогоор онцлох зар байхгүй байна.</p>
                  </div>
                )}
              </div>
            )}
          </div>
        </section>
        
        {/* Call to Action */}
        <section className="relative rounded-[4rem] overflow-hidden bg-primary px-8 py-32 text-center text-primary-foreground shadow-[0_32px_64px_-12px_rgba(0,0,0,0.1)] mb-12">
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_right,rgba(255,255,255,0.15),transparent)]" />
          <div className="relative z-10 max-w-3xl mx-auto space-y-10">
            <h2 className="text-5xl md:text-8xl font-[1000] tracking-tighter leading-none">Танд зарах зүйл байна уу?</h2>
            <p className="text-primary-foreground/80 text-xl md:text-2xl font-medium max-w-2xl mx-auto leading-relaxed">
              Хэдхэн минутын дотор зарах зүйлийнхээ зургийг авч, мэдээллээ оруулаад мянга мянган худалдан авагчдад хүргээрэй.
            </p>
            <Button render={<Link href="/create" />} size="xl" variant="secondary" className="rounded-[2rem] px-16 h-20 text-2xl font-black shadow-2xl hover:scale-105 active:scale-95 transition-all">
              Зар оруулах
            </Button>
          </div>
        </section>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { 
  User as UserIcon, 
  Settings, 
  Heart, 
  Package, 
  LogOut, 
  ShieldCheck, 
  Calendar, 
  Phone, 
  Mail, 
  ChevronRight,
  PlusCircle,
  ExternalLink,
  CheckCircle2,
  AlertCircle
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { Button } from '../../components/ui/button';
import { Input } from '../../components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '../../components/ui/avatar';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../../components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../../components/ui/tabs';
import { Badge } from '../../components/ui/badge';
import { Separator } from '../../components/ui/separator';
import { Skeleton } from '../../components/ui/skeleton';
import ListingCard from '../../components/ListingCard';
import { Listing } from '../../types';
import { fetcher } from '../../utils/api';
import { supabase } from '../../utils/supabase';

export default function ProfilePage() {
  const { user, loading: authLoading, logout } = useAuth();
  const [myListings, setMyListings] = useState<Listing[]>([]);
  const [loadingListings, setLoadingListings] = useState(false);
  const [adminRequest, setAdminRequest] = useState<any>(null);
  const [loadingAdminRequest, setLoadingAdminRequest] = useState(false);
  const [adminRequestError, setAdminRequestError] = useState<string | null>(null);

  useEffect(() => {
    if (user) {
      setLoadingListings(true);
      fetcher(`/listings?userId=${user.id}`)
        .then(setMyListings)
        .catch(console.error)
        .finally(() => setLoadingListings(false));
    }
  }, [user]);

  useEffect(() => {
    if (!user) {
      setAdminRequest(null);
      return;
    }

    setLoadingAdminRequest(true);
    setAdminRequestError(null);

    supabase
      .from('admin_requests')
      .select('status, requested_at')
      .eq('user_id', user.id)
      .maybeSingle()
      .then(({ data, error }) => {
        if (error) throw error;
        setAdminRequest(data);
      })
      .catch((e: any) => {
        setAdminRequestError(e?.message || 'Failed to load admin request');
        setAdminRequest(null);
      })
      .finally(() => setLoadingAdminRequest(false));
  }, [user]);

  const handleRequestAdmin = async () => {
    if (!user) return;
    setAdminRequestError(null);
    setLoadingAdminRequest(true);

    const user_metadata = user.user_metadata || {};

    try {
      await supabase.from('admin_requests').upsert(
        {
          user_id: user.id,
          user_name: user_metadata.name || '',
          user_email: user.email || '',
          user_phone: user_metadata.phone || null,
          user_avatar: user_metadata.avatar || null,
          status: 'pending',
          requested_at: new Date().toISOString(),
        },
        { onConflict: 'user_id' }
      );

      const { data, error } = await supabase
        .from('admin_requests')
        .select('status, requested_at')
        .eq('user_id', user.id)
        .maybeSingle();

      if (error) throw error;
      setAdminRequest(data);
    } catch (e: any) {
      setAdminRequestError(e?.message || 'Failed to submit admin request');
    } finally {
      setLoadingAdminRequest(false);
    }
  };

  if (authLoading) {
    return (
      <div className="max-w-5xl mx-auto py-10 space-y-8 px-4">
        <div className="flex flex-col md:flex-row gap-8 items-start">
          <Skeleton className="h-64 w-full md:w-[300px] rounded-[2.5rem]" />
          <div className="flex-grow space-y-6 w-full">
            <Skeleton className="h-20 w-full rounded-3xl" />
            <Skeleton className="h-[400px] w-full rounded-3xl" />
          </div>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center text-center space-y-6 px-4">
        <div className="w-24 h-24 rounded-full bg-muted flex items-center justify-center">
          <UserIcon className="h-12 w-12 text-muted-foreground" />
        </div>
        <div className="space-y-2 max-w-sm">
          <h1 className="text-3xl font-black tracking-tight">Нэвтрэх шаардлагатай</h1>
          <p className="text-muted-foreground">
            Өөрийн профиль болон заруудаа удирдахын тулд системд нэвтэрнэ үү.
          </p>
        </div>
        <Button render={<Link href="/login" />} size="xl" className="rounded-2xl px-10 h-14 text-lg font-bold shadow-xl shadow-primary/20">
          Нэвтрэх
        </Button>
      </div>
    );
  }

  const { user_metadata } = user;

  return (
    <div className="max-w-7xl mx-auto py-6 md:py-10 px-4 space-y-10">
      <div className="flex flex-col lg:flex-row gap-10 items-start">
        {/* Left: User Info Card */}
        <aside className="w-full lg:w-[350px] space-y-6 lg:sticky lg:top-24">
          <Card className="rounded-[2.5rem] border-none shadow-2xl overflow-hidden bg-card">
            <div className="h-32 bg-gradient-to-br from-primary via-primary/80 to-blue-600" />
            <CardContent className="p-8 -mt-16 text-center space-y-6">
              <div className="relative inline-block">
                <Avatar className="h-32 w-32 border-4 border-background shadow-2xl">
                  <AvatarImage src={user_metadata.avatar} className="object-cover" />
                  <AvatarFallback className="text-4xl bg-muted text-muted-foreground">{user_metadata.name?.charAt(0)}</AvatarFallback>
                </Avatar>
                {user_metadata.is_verified && (
                  <div className="absolute bottom-1 right-1 bg-blue-500 rounded-full p-1.5 border-4 border-background">
                    <CheckCircle2 className="h-5 w-5 text-white" />
                  </div>
                )}
              </div>
              
              <div className="space-y-1">
                <h1 className="text-2xl font-black tracking-tight">{user_metadata.name}</h1>
                <p className="text-muted-foreground text-sm font-medium">{user.email}</p>
              </div>

              <div className="flex flex-wrap justify-center gap-2">
                {user_metadata.is_verified ? (
                  <Badge variant="secondary" className="bg-blue-500/10 text-blue-600 hover:bg-blue-500/20 border-none px-4 py-1 rounded-full font-bold text-[10px] uppercase tracking-widest">
                    Баталгаажсан
                  </Badge>
                ) : (
                  <Badge variant="outline" className="border-dashed px-4 py-1 rounded-full font-bold text-[10px] uppercase tracking-widest text-muted-foreground">
                    Баталгаажаагүй
                  </Badge>
                )}
              </div>

              <Separator />

              <div className="space-y-4 text-left">
                <div className="flex items-center gap-3 text-sm">
                  <div className="h-9 w-9 rounded-xl bg-muted flex items-center justify-center shrink-0">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                  </div>
                  <div>
                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Гишүүнээр элссэн</p>
                    <p className="font-bold">{user.created_at ? new Date(user.created_at).getFullYear() : '—'} он</p>
                  </div>
                </div>

                {user_metadata.phone && (
                  <div className="flex items-center gap-3 text-sm">
                    <div className="h-9 w-9 rounded-xl bg-muted flex items-center justify-center shrink-0">
                      <Phone className="h-4 w-4 text-muted-foreground" />
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider">Утас</p>
                      <p className="font-bold">{user_metadata.phone}</p>
                    </div>
                  </div>
                )}
              </div>

              <Button variant="outline" className="w-full rounded-2xl h-12 font-bold border-2 group" onClick={logout}>
                <LogOut className="h-4 w-4 mr-2 group-hover:text-red-500 transition-colors" /> Системээс гарах
              </Button>
            </CardContent>
          </Card>

          <Card className="rounded-[2.5rem] border-none shadow-xl bg-slate-50 dark:bg-zinc-900/50">
            <CardContent className="p-6 space-y-4">
              <h3 className="font-bold text-sm uppercase tracking-widest text-muted-foreground px-2">Тусламж</h3>
              <div className="space-y-1">
                <Button variant="ghost" className="w-full justify-between rounded-xl h-12 font-medium">
                  Нууц үг солих <ChevronRight className="h-4 w-4 opacity-50" />
                </Button>
                <Button variant="ghost" className="w-full justify-between rounded-xl h-12 font-medium">
                  Аюулгүй байдал <ChevronRight className="h-4 w-4 opacity-50" />
                </Button>
                <Button variant="ghost" className="w-full justify-between rounded-xl h-12 font-medium text-red-500 hover:text-red-600 hover:bg-red-500/5">
                  Хаяг устгах <ChevronRight className="h-4 w-4 opacity-50" />
                </Button>
              </div>
            </CardContent>
          </Card>
        </aside>

        {/* Right: Tabs & Content */}
        <main className="flex-grow space-y-8 w-full">
          <Tabs defaultValue="listings" className="w-full space-y-8">
            <div className="bg-card p-2 rounded-[2rem] shadow-sm border border-border/50 inline-flex w-full md:w-auto">
              <TabsList className="bg-transparent h-auto p-0 flex flex-wrap md:flex-nowrap w-full">
                <TabsTrigger 
                  value="listings" 
                  className="rounded-2xl px-8 py-3 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-xl font-bold transition-all flex-1 md:flex-none"
                >
                  <Package className="h-4 w-4 mr-2" /> Миний зарууд
                </TabsTrigger>
                <TabsTrigger 
                  value="favorites" 
                  className="rounded-2xl px-8 py-3 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-xl font-bold transition-all flex-1 md:flex-none"
                >
                  <Heart className="h-4 w-4 mr-2" /> Хадгалсан
                </TabsTrigger>
                <TabsTrigger 
                  value="settings" 
                  className="rounded-2xl px-8 py-3 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground data-[state=active]:shadow-xl font-bold transition-all flex-1 md:flex-none"
                >
                  <Settings className="h-4 w-4 mr-2" /> Тохиргоо
                </TabsTrigger>
              </TabsList>
            </div>

            <TabsContent value="listings" className="space-y-8 mt-0 focus-visible:outline-none">
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-bold tracking-tight">Нийтэлсэн зарууд</h2>
                  <p className="text-muted-foreground text-sm">Таны одоогоор идэвхтэй байгаа зарууд</p>
                </div>
                <Button render={<Link href="/create" />} className="gap-2 rounded-2xl px-6 h-12 font-bold shadow-xl shadow-primary/20 hover:scale-105 active:scale-95 transition-all">
                  <PlusCircle className="h-4 w-4" />
                  <span>Шинэ зар</span>
                </Button>
              </div>

              {loadingListings ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {[...Array(3)].map((_, i) => <Skeleton key={i} className="h-96 rounded-3xl" />)}
                </div>
              ) : myListings.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {myListings.map(listing => <ListingCard key={listing.id} listing={listing} />)}
                </div>
              ) : (
                <div className="text-center py-20 bg-muted rounded-3xl space-y-4">
                  <h3 className="text-xl font-bold">Илэрц олдсонгүй</h3>
                  <p className="text-muted-foreground">Та одоогоор ямар ч зар нийтлээгүй байна.</p>
                  <Button render={<Link href="/create" />} size="lg" className="rounded-xl mt-4">
                    Анхны зараа оруулах
                  </Button>
                </div>
              )}
            </TabsContent>

            <TabsContent value="favorites" className="space-y-6 mt-0 focus-visible:outline-none">
              <h2 className="text-2xl font-bold tracking-tight">Хадгалсан зарууд</h2>
              {/* Favorites content here */}
              <div className="text-center py-20 bg-muted rounded-3xl space-y-4">
                <h3 className="text-xl font-bold">Илэрц олдсонгүй</h3>
                <p className="text-muted-foreground">Та одоогоор ямар ч зар хадгалаагүй байна.</p>
              </div>
            </TabsContent>

            <TabsContent value="settings" className="space-y-6 mt-0 focus-visible:outline-none">
              <h2 className="text-2xl font-bold tracking-tight">Тохиргоо</h2>
              {/* Settings content here */}
                <Card className="rounded-3xl">
                  <CardContent className="p-8 space-y-4">
                    <div className="flex items-start justify-between gap-4">
                      <div className="space-y-1">
                        <h3 className="font-bold text-lg">Админ эрх (status)</h3>
                        <p className="text-muted-foreground text-sm">
                          Админ болох хүсэлтээ илгээх болон статус шалгах бол тусдаа хуудсанд орно.
                        </p>
                      </div>

                      <Badge
                        variant="secondary"
                        className="bg-blue-500/10 text-blue-700 border-none px-4 py-1 rounded-full font-bold text-[10px] uppercase tracking-widest"
                      >
                        {adminRequest?.status === 'approved'
                          ? 'Approved'
                          : adminRequest?.status === 'pending'
                          ? 'Pending'
                          : adminRequest?.status === 'rejected'
                          ? 'Rejected'
                          : 'Not requested'}
                      </Badge>
                    </div>

                    {adminRequestError && (
                      <div className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-2xl px-4 py-3">
                        {adminRequestError}
                      </div>
                    )}

                    <div className="flex flex-col sm:flex-row gap-3 sm:items-center sm:justify-between">
                      <p className="text-muted-foreground text-sm">
                        {adminRequest?.status === 'pending'
                          ? `Хүсэлт хүлээгдэж байна (${adminRequest.requested_at ? new Date(adminRequest.requested_at).toLocaleString() : '—'})`
                          : adminRequest?.status === 'approved'
                          ? 'Таны хүсэлт зөвшөөрөгдсөн.'
                          : adminRequest?.status === 'rejected'
                          ? 'Таны хүсэлт татгалзсан. Дахин хүсэлт явуулж болно.'
                          : 'Хүсэлт илгээх шаардлагатай.'}
                      </p>

                      <Button
                        render={<Link href="/admin/request" />}
                        className="rounded-2xl px-8 h-12 font-black shadow-xl shadow-primary/20 hover:scale-105 active:scale-95 transition-all"
                      >
                        Админ хүсэлт ба статус
                      </Button>
                    </div>
                  </CardContent>
                </Card>

              <Card className="rounded-3xl">
                <CardContent className="p-8">
                  <h3 className="font-bold mb-4">Профайл засах</h3>
                  <div className="space-y-4">
                    <Input placeholder="Нэр" defaultValue={user_metadata.name} />
                    <Input placeholder="Утасны дугаар" defaultValue={user_metadata.phone} />
                    <Button>Хадгалах</Button>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>
          </Tabs>
        </main>
      </div>
    </div>
  );
}

import Link from 'next/link';
import { Heart, MapPin, CheckCircle2 } from 'lucide-react';
import { Card, CardContent, CardFooter } from './ui/card';
import { Badge } from './ui/badge';
import { Button } from './ui/button';
import { Avatar, AvatarFallback, AvatarImage } from './ui/avatar';
import { Listing } from '../types';

interface ListingCardProps {
  listing: Listing;
}

const ListingCard: React.FC<ListingCardProps> = ({ listing }) => {
  const formattedPrice = new Intl.NumberFormat('mn-MN', {
    style: 'currency',
    currency: 'MNT',
    maximumFractionDigits: 0,
  }).format(listing.price);

  const mainImage = listing.images?.[0] || 'https://images.unsplash.com/photo-1580587771525-78b9dba3b914?auto=format&fit=crop&q=80&w=800';

  return (
    <Card className="group overflow-hidden border-none shadow-md hover:shadow-xl transition-all duration-300 rounded-2xl bg-card">
      <Link href={`/listings/${listing.id}`} className="block relative aspect-[4/3] overflow-hidden">
        <img
          src={mainImage}
          alt={listing.title}
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
        
        <div className="absolute top-3 right-3 z-10">
          <Button
            variant="secondary"
            size="icon"
            className="h-8 w-8 rounded-full bg-white/80 backdrop-blur-sm hover:bg-white text-gray-900 shadow-sm border-none"
            onClick={(e: React.MouseEvent) => {
              e.preventDefault();
              e.stopPropagation();
              // Add favorite logic here
            }}
          >
            <Heart className="h-4 w-4" />
          </Button>
        </div>

        {listing.category && (
          <div className="absolute bottom-3 left-3 z-10">
            <Badge variant="secondary" className="bg-white/90 backdrop-blur-sm text-gray-900 font-medium border-none text-[10px] px-2 py-0">
              {listing.category}
            </Badge>
          </div>
        )}
      </Link>

      <CardContent className="p-4">
        <Link href={`/listings/${listing.id}`}>
          <div className="space-y-1.5">
            <div className="flex items-center justify-between gap-2">
              <span className="text-base font-bold text-primary tracking-tight">
                {formattedPrice}
              </span>
            </div>
            <h3 className="font-semibold text-foreground line-clamp-2 leading-snug group-hover:text-primary transition-colors h-[2.8rem]">
              {listing.title}
            </h3>
            <div className="flex items-center text-muted-foreground text-xs gap-1 pt-1">
              <MapPin className="h-3 w-3 shrink-0" />
              <span className="truncate">{listing.location}</span>
            </div>
          </div>
        </Link>
      </CardContent>

      <CardFooter className="px-4 pb-4 pt-0 flex items-center justify-between border-t border-border/40 mt-auto pt-3">
        <div className="flex items-center gap-2">
          <Avatar className="h-6 w-6 border border-border">
            <AvatarImage src={listing.user?.avatar} />
            <AvatarFallback className="text-[10px]">{listing.user?.name?.charAt(0) || 'U'}</AvatarFallback>
          </Avatar>
          <div className="flex items-center gap-1 overflow-hidden">
            <span className="text-[11px] font-medium text-foreground truncate max-w-[80px]">
              {listing.user?.name || 'Хэрэглэгч'}
            </span>
            {listing.user?.isVerified && (
              <CheckCircle2 className="h-3 w-3 text-blue-500 shrink-0" />
            )}
          </div>
        </div>
        <span className="text-[10px] text-muted-foreground font-medium">
          {new Date(listing.createdAt).toLocaleDateString('mn-MN', {
            month: 'short',
            day: 'numeric'
          })}
        </span>
      </CardFooter>
    </Card>
  );
};

export default ListingCard;

'use client';

import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { Button } from './ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from './ui/dropdown-menu';
import { Avatar, AvatarFallback, AvatarImage } from './ui/avatar';
import {
  Search,
  PlusCircle,
  MessageSquare,
  User,
  LogOut,
  Settings,
  Heart,
  Menu,
  Moon,
  Sun,
} from 'lucide-react';
import { useTheme } from 'next-themes';
import { Sheet, SheetContent, SheetTrigger } from './ui/sheet';
import { Separator } from './ui/separator';
import { supabase } from '../utils/supabase';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { setTheme, theme } = useTheme();
  const router = useRouter();
  const [searchQuery, setSearchQuery] = useState('');
  const [isAdmin, setIsAdmin] = useState(false);
  const [checkingAdmin, setCheckingAdmin] = useState(false);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      router.push(`/listings?search=${encodeURIComponent(searchQuery.trim())}`);
    }
  };

  // Only admins should see `/admin` link.
  useEffect(() => {
    const load = async () => {
      if (!user) {
        setIsAdmin(false);
        return;
      }

      setCheckingAdmin(true);
      try {
        const { data, error } = await supabase
          .from('admin_requests')
          .select('status')
          .eq('user_id', user.id)
          .eq('status', 'approved')
          .maybeSingle();

        if (error) throw error;
        setIsAdmin(!!data);
      } catch {
        setIsAdmin(false);
      } finally {
        setCheckingAdmin(false);
      }
    };

    load();
  }, [user]);

  return (
    <header className="sticky top-0 z-50 w-full border-b bg-background/80 backdrop-blur-xl supports-[backdrop-filter]:bg-background/60">
      <div className="max-w-[1400px] mx-auto px-4 md:px-8 h-20 flex items-center gap-4 md:gap-8">
        {/* Left: Logo & Nav */}
        <div className="flex items-center gap-8 shrink-0">
          <Link href="/" className="flex items-center space-x-2 group">
            <div className="rounded-xl bg-primary p-1.5 shadow-lg shadow-primary/20 group-hover:scale-110 transition-transform duration-300">
              <Search className="h-5 w-5 text-primary-foreground stroke-[3px]" />
            </div>
            <span className="text-2xl font-black tracking-tighter text-primary">UNEGUI</span>
          </Link>

          <nav className="hidden lg:flex items-center gap-6 text-[15px] font-bold">
            <Link href="/" className="text-muted-foreground hover:text-primary transition-colors">Нүүр</Link>
            <Link href="/listings" className="text-muted-foreground hover:text-primary transition-colors">Зарууд</Link>
            {isAdmin && (
              <Link href="/admin" className="text-muted-foreground hover:text-primary transition-colors">
                Админ
              </Link>
            )}
          </nav>
        </div>

        {/* Center: Search Bar */}
        <div className="flex-grow hidden md:flex items-center justify-center max-w-2xl mx-auto">
          <form onSubmit={handleSearch} className="relative w-full group">
            <div className="absolute inset-0 bg-primary/5 rounded-2xl blur-md opacity-0 group-focus-within:opacity-100 transition-opacity" />
            <div className="relative flex items-center bg-muted/50 rounded-2xl border-2 border-transparent focus-within:border-primary/20 focus-within:bg-background transition-all duration-300 overflow-hidden">
              <Search className="absolute left-4 h-4 w-4 text-muted-foreground group-focus-within:text-primary transition-colors" />
              <input
                placeholder="Хайх..."
                className="h-12 w-full bg-transparent pl-12 pr-4 text-sm font-medium focus:outline-none"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </form>
        </div>

        {/* Right: Actions */}
        <div className="flex items-center gap-2 md:gap-4 shrink-0">
          {user ? (
            <div className="flex items-center gap-2 md:gap-3">
              <Button render={<Link href="/chat" />} variant="ghost" size="icon" className="rounded-full hover:bg-primary/5 hover:text-primary transition-all">
                <MessageSquare className="h-5 w-5" />
              </Button>
              
              <Button render={<Link href="/profile" />} variant="ghost" size="icon" className="rounded-full hover:bg-primary/5 hover:text-primary transition-all">
                <Heart className="h-5 w-5" />
              </Button>

              <Button render={<Link href="/create" />} variant="default" className="hidden sm:flex gap-2 rounded-2xl px-6 h-12 font-bold shadow-xl shadow-primary/20 hover:scale-105 active:scale-95 transition-all">
                <PlusCircle className="h-4 w-4" />
                <span>Зар оруулах</span>
              </Button>

              <DropdownMenu>
                <DropdownMenuTrigger render={<Button variant="ghost" className="relative h-11 w-11 rounded-full border-2 border-transparent hover:border-primary/20 p-0 transition-all" />}>
                  <Avatar className="h-10 w-10">
                    <AvatarImage src={user.user_metadata.avatar} alt={user.user_metadata.name} />
                    <AvatarFallback className="bg-primary/10 text-primary font-bold">{user.user_metadata.name?.charAt(0)}</AvatarFallback>
                  </Avatar>
                </DropdownMenuTrigger>
                <DropdownMenuContent className="w-64 p-2 rounded-3xl" align="end">
                  <DropdownMenuGroup>
                    <DropdownMenuLabel className="font-normal p-4">
                      <div className="flex flex-col space-y-1">
                        <p className="text-sm font-bold leading-none">{user.user_metadata.name}</p>
                        <p className="text-xs leading-none text-muted-foreground">{user.email}</p>
                      </div>
                    </DropdownMenuLabel>
                  </DropdownMenuGroup>
                  <DropdownMenuSeparator className="my-2" />
                  <DropdownMenuItem render={<Link href="/profile" className="flex w-full items-center font-bold p-3 rounded-xl" />}>
                    <User className="mr-3 h-4 w-4" />
                    <span>Профайл</span>
                  </DropdownMenuItem>
                  <DropdownMenuItem render={<Link href="/profile" className="flex w-full items-center font-bold p-3 rounded-xl" />}>
                    <Settings className="mr-3 h-4 w-4" />
                    <span>Тохиргоо</span>
                  </DropdownMenuItem>
                  <DropdownMenuSeparator className="my-2" />
                  <DropdownMenuItem onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="font-bold p-3 rounded-xl">
                    {theme === 'dark' ? <Sun className="mr-3 h-4 w-4" /> : <Moon className="mr-3 h-4 w-4" />}
                    <span>{theme === 'dark' ? 'Гэрэлтэй' : 'Харанхуй'}</span>
                  </DropdownMenuItem>
                  <DropdownMenuSeparator className="my-2" />
                  <DropdownMenuItem onClick={logout} className="text-destructive focus:bg-destructive/10 focus:text-destructive font-bold p-3 rounded-xl">
                    <LogOut className="mr-3 h-4 w-4" />
                    <span>Гарах</span>
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          ) : (
            <div className="flex items-center gap-2 md:gap-3">
              <Button variant="ghost" render={<Link href="/login" />} className="font-bold rounded-2xl h-12 px-6 hover:bg-primary/5 transition-all">
                Нэвтрэх
              </Button>
              <Button render={<Link href="/register" />} className="rounded-2xl px-8 h-12 font-black shadow-xl shadow-primary/20 hover:scale-105 active:scale-95 transition-all">
                Бүртгүүлэх
              </Button>
            </div>
          )}

          <Sheet>
            <SheetTrigger render={<Button variant="ghost" size="icon" className="lg:hidden rounded-full h-11 w-11" />}>
              <Menu className="h-6 w-6" />
            </SheetTrigger>

            <SheetContent side="right" className="w-[300px] rounded-l-[2.5rem] p-8">
              <div className="flex flex-col gap-8 mt-12">
                <Link href="/" className="text-3xl font-black hover:text-primary transition-colors">Нүүр</Link>
                <Link href="/listings" className="text-3xl font-black hover:text-primary transition-colors">Зарууд</Link>
                {user && (
                  <>
                    <Link href="/chat" className="text-3xl font-black hover:text-primary transition-colors">Чат</Link>
                    <Link href="/profile" className="text-3xl font-black hover:text-primary transition-colors">Профиль</Link>
                    <Separator className="my-2" />
                    <Link href="/create" className="text-3xl font-black text-primary hover:opacity-80 transition-all">Зар оруулах</Link>
                    {isAdmin ? (
                      <Link href="/admin" className="text-3xl font-black hover:text-primary transition-colors">
                        Админ
                      </Link>
                    ) : (
                      <Link href="/admin/request" className="text-3xl font-black hover:text-primary transition-colors">
                        Админ хүсэлт
                      </Link>
                    )}
                  </>
                )}
              </div>
            </SheetContent>
          </Sheet>
        </div>
      </div>
    </header>
  );
};

export default Navbar;

'use client';

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Session, User } from '@supabase/supabase-js';
import { supabase } from '../utils/supabase';
import { fetcher } from '../utils/api';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const getSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    };

    getSession();

    const { data: authListener } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setUser(session?.user ?? null);
    });

    return () => {
      authListener.subscription.unsubscribe();
    };
  }, []);

  const logout = async () => {
    await supabase.auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, session, loading, logout }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
